#include <stdio.h>

int main() {
    int n;
    if (scanf("%d", &n) != 1) return 0;
    int val;
    scanf("%d", &val);
    int largest = val, smallest = val;
    for (int i = 1; i < n; ++i) {
        scanf("%d", &val);
        if (val > largest) largest = val;
        if (val < smallest) smallest = val;
    }
    printf("Largest: %d\n", largest);
    printf("Smallest: %d\n", smallest);
    return 0;
}

