import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    n = int(next(it))
    first = int(next(it))
    largest = smallest = first
    for _ in range(n-1):
        val = int(next(it))
        if val > largest:
            largest = val
        if val < smallest:
            smallest = val
    sys.stdout.write(f"Largest: {largest}\nSmallest: {smallest}\n")

if __name__ == "__main__":
    main()

